INSERT INTO tb_project (title, body, image, user_id) VALUES ('Agrobairros',                         'Os projetos urbanos que combinam casas e áreas de produção de alimentos solucionam duas demandas de quem vive em cidades: um contato maior com a natureza e a proximidade com a produção de alimentos – o que gera menos impacto ambiental e, muitas vezes, acesso à comida produzida de maneira mais saudável e sustentável. Nesta publicação, veja mais sobre quais conteúdos didáticos, eventos e atividades que estão relacionadas aos Agrobairros em Caxias', 'https://www.graphikmaquetas.com.ar/val8.jpg', 1);
INSERT INTO tb_project (title, body, image, user_id) VALUES ('Coleta e Filtragem de Água',          'Os projetos de coleta e filtragem de água visão prover a criação de estruturas que possam sar facilmente instaladas em diversos locais da cidade permitindo também que a água da chuva seja coletada, filtrada e armazenada para os períodos mais secos, auxiliando na gestão sustentável da água. Nesta publicação, veja mais sobre quais conteúdos didáticos, eventos e atividades que estão relacionadas a Coleta e Filtragem de Água em Caxias', 'https://img.freepik.com/premium-vector/water-drop-shape-blue-water-drop-logo-design-water-oil-drop_275352-810.jpg', 2);
INSERT INTO tb_project (title, body, image, user_id) VALUES ('Arquitetura Acessível e Sutentável',  'Os projetos de moradia que envolvem uma arquitetura de preço acessível, uma alta velocidade na produção e um baixo impacto no meito ambiente podem ser uma solução prática para o problema de pessoas em situação de vunerabilidade com moradia. Nesta publicação, veja mais sobre quais conteúdos didáticos, eventos e atividades que estão relacionadas a Arquitetura Acessível e Sustentável em Caxias', 'https://files.prokerala.com/news/photos/imgs/1024/telangana-mobility-valley-1522957.jpg', 3);
INSERT INTO tb_project (title, body, image, user_id) VALUES ('Reurbanização',                       'Os projetos de reurbanização são iram pertimitir a reorganização do espaço urbano e a implantação da infraestrutura necessária em um determinado contexto. Nesta publicação, veja mais sobre quais conteúdos didáticos, eventos e atividades que estão relacionadas a Reurbanização em Caxias', 'https://files.prokerala.com/news/photos/imgs/1024/telangana-mobility-valley-1522957.jpg', 4);
INSERT INTO tb_project (title, body, image, user_id) VALUES ('Inovação Tecnológica na Educação',    'Nesta publicação, veja mais sobre quais conteúdos didáticos, eventos e atividades que estão relacionadas a Invovação Tecnológica na Educação em Caxias', 'https://neetable.com/img/blog/blog-inner/the-role-of-future-education/the-role-of-future-education.jpg', 5);
INSERT INTO tb_project (title, body, image, user_id) VALUES ('Presevação de Bairros Históricos',    'Nesta publicação, veja mais sobre quais conteúdos didáticos, eventos e atividades que estão relacionadas a Preservação de Bairros Históricos em Caxias', 'https://files.prokerala.com/news/photos/imgs/1024/telangana-mobility-valley-1522957.jpg', 6);
